import React, { useEffect, useState } from 'react';
import { getProducts } from '../services/productService';
import ProductCard from '../components/organisms/ProductCard/ProductCard';
import CartView from '../components/organisms/Cart/CartView';
import { useCart } from '../context/CartContext';
import { Button } from '../components/atoms';
import { useNavigate, useLocation } from 'react-router-dom';
import { getUserByPhone } from '../services/userService';
import './EmployeeDashboard.css';

export default function EmployeeDashboard() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState("Todos");
  const { cartItems, subtotal, tax, total } = useCart();
  const navigate = useNavigate();
  const location = useLocation();

  // Client Selection States
  const [clientTab, setClientTab] = useState('invitado'); // 'invitado' | 'buscar'
  const [searchPhone, setSearchPhone] = useState('');
  const [selectedClient, setSelectedClient] = useState(null);
  const [searching, setSearching] = useState(false);
  const [searchError, setSearchError] = useState('');

  // Auto-select client when returning from /register-client
  useEffect(() => {
    if (location.state?.registeredPhone) {
      const autoFetch = async () => {
        setSearching(true);
        setSearchError('');
        try {
          const data = await getUserByPhone(location.state.registeredPhone);
          setSelectedClient(data);
          setClientTab('buscar');
          setSearchPhone(location.state.registeredPhone);
        } catch (error) {
          console.error("Error auto-fetching client:", error);
        } finally {
          setSearching(false);
        }
      };
      autoFetch();
      // Clear the history state
      window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  const handleSearchClient = async () => {
    if (!searchPhone.trim()) {
      setSearchError('Por favor ingresa un número de teléfono');
      return;
    }
    setSearching(true);
    setSearchError('');
    try {
      const data = await getUserByPhone(searchPhone.trim());
      setSelectedClient(data);
    } catch (error) {
      if (error.response?.status === 404) {
        // Redirigir directamente a registrar cliente pre-llenando el telefono
        navigate('/register-client', { state: { phone: searchPhone.trim() } });
      } else {
        setSearchError(error.response?.data?.error || 'Error al buscar el cliente');
      }
    } finally {
      setSearching(false);
    }
  };

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const data = await getProducts();
        // Assuming data is an array or has a data property
        setProducts(data.data || data || []);
      } catch (error) {
        console.error("Error fetching products", error);
      } finally {
        setLoading(false);
      }
    };
    fetchProducts();
  }, []);

  // Get unique categories from products
  const categories = ["Todos", ...new Set(products.map(p => p.category).filter(Boolean))];

  const filteredProducts = selectedCategory === "Todos"
    ? products
    : products.filter(p => p.category === selectedCategory);

  return (
    <div className="employee-dashboard">
      <div className="products-section">
        <div className="employee-actions" style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', marginBottom: '1.5rem' }}>
          <h2>Productos</h2>

          {/* Category Filter Tabs */}
          {!loading && (
            <div className="category-tabs" style={{ display: 'flex', gap: '0.5rem', overflowX: 'auto', paddingBottom: '0.5rem' }}>
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  style={{
                    padding: '0.4rem 1rem',
                    borderRadius: '20px',
                    border: '1px solid #e2e8f0',
                    backgroundColor: selectedCategory === cat ? '#22c55e' : '#ffffff',
                    color: selectedCategory === cat ? '#ffffff' : '#475569',
                    cursor: 'pointer',
                    fontWeight: '600',
                    fontSize: '0.85rem',
                    whiteSpace: 'nowrap',
                    transition: 'all 0.2s ease',
                    boxShadow: '0 1px 2px rgba(0,0,0,0.05)'
                  }}
                >
                  {cat}
                </button>
              ))}
            </div>
          )}
        </div>

        {loading ? (
          <p>Cargando productos...</p>
        ) : (
          <div className="products-list">
            {filteredProducts.map(product => (
              <ProductCard key={product._id} product={product} orientation="horizontal" />
            ))}
          </div>
        )}
      </div>

      <div className="cart-section">
        <div className="cart-actions-header" style={{ padding: '1rem', borderBottom: '1px solid #e1e4e8', display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
          <h3 style={{ margin: 0, fontSize: '1.1rem' }}>Orden Actual</h3>
          <Button variant="secondary" onClick={() => navigate('/orders')} style={{ padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}>Ver Órdenes</Button>
        </div>

        <div className="client-selection-container" style={{
          padding: '1rem',
          borderBottom: '1px solid #e1e4e8',
          backgroundColor: clientTab === 'invitado' ? '#f0fdf4' : '#f8fafc',
          borderLeft: clientTab === 'invitado' ? '4px solid #22c55e' : 'none',
          transition: 'all 0.3s ease'
        }}>
          <h4 style={{ margin: '0 0 0.5rem 0', color: '#1e293b', fontSize: '0.9rem', fontWeight: 'bold' }}>Cliente para la venta:</h4>

          <div className="client-tabs" style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.75rem' }}>
            <button
              onClick={() => {
                setClientTab('invitado');
                setSelectedClient(null);
                setSearchPhone('');
                setSearchError('');
              }}
              style={{
                flex: 1,
                padding: '0.5rem',
                fontSize: '0.8rem',
                fontWeight: 'bold',
                borderRadius: '6px',
                border: '1px solid',
                borderColor: clientTab === 'invitado' ? '#22c55e' : '#cbd5e1',
                backgroundColor: clientTab === 'invitado' ? '#22c55e' : '#ffffff',
                color: clientTab === 'invitado' ? '#ffffff' : '#64748b',
                cursor: 'pointer',
                transition: 'all 0.2s',
                boxShadow: clientTab === 'invitado' ? '0 2px 4px rgba(34,197,94,0.2)' : 'none'
              }}
            >
              Invitado
            </button>
            <button
              onClick={() => {
                setClientTab('buscar');
                setSearchError('');
              }}
              style={{
                flex: 1,
                padding: '0.5rem',
                fontSize: '0.8rem',
                fontWeight: 'bold',
                borderRadius: '6px',
                border: '1px solid',
                borderColor: clientTab === 'buscar' ? '#3b82f6' : '#cbd5e1',
                backgroundColor: clientTab === 'buscar' ? '#3b82f6' : '#ffffff',
                color: clientTab === 'buscar' ? '#ffffff' : '#64748b',
                cursor: 'pointer',
                transition: 'all 0.2s',
                boxShadow: clientTab === 'buscar' ? '0 2px 4px rgba(59,130,246,0.2)' : 'none'
              }}
            >
              Ya es Cliente
            </button>
            <button
              onClick={() => {
                navigate('/register-client', { state: { phone: searchPhone } });
              }}
              style={{
                flex: 1,
                padding: '0.5rem',
                fontSize: '0.8rem',
                fontWeight: 'bold',
                borderRadius: '6px',
                border: '1px solid #cbd5e1',
                backgroundColor: '#ffffff',
                color: '#64748b',
                cursor: 'pointer',
                transition: 'all 0.2s'
              }}
            >
              Registrar Cliente
            </button>
          </div>

          {clientTab === 'invitado' && (
            <div style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: '0.5rem',
              backgroundColor: '#dcfce7',
              border: '1px solid #22c55e',
              borderRadius: '6px',
              color: '#15803d',
              fontSize: '0.8rem',
              fontWeight: '600'
            }}>
              ✓ INVITADO (Venta directa rápida)
            </div>
          )}

          {clientTab === 'buscar' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
              {!selectedClient ? (
                <>
                  <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <input
                      type="tel"
                      placeholder="Número de Teléfono..."
                      value={searchPhone}
                      onChange={(e) => setSearchPhone(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') handleSearchClient();
                      }}
                      style={{
                        flex: 1,
                        padding: '0.4rem 0.6rem',
                        fontSize: '0.85rem',
                        borderRadius: '4px',
                        border: '1px solid #cbd5e1',
                        outline: 'none'
                      }}
                    />
                    <button
                      onClick={handleSearchClient}
                      disabled={searching}
                      style={{
                        padding: '0.4rem 0.8rem',
                        fontSize: '0.85rem',
                        fontWeight: 'bold',
                        backgroundColor: '#3b82f6',
                        color: '#ffffff',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        transition: 'opacity 0.2s'
                      }}
                    >
                      {searching ? 'Buscando...' : 'Validar'}
                    </button>
                  </div>
                  {searchError && (
                    <span style={{ color: '#ef4444', fontSize: '0.75rem', fontWeight: '500' }}>
                      {searchError}
                    </span>
                  )}
                </>
              ) : (
                <div style={{
                  padding: '0.6rem',
                  backgroundColor: '#f0fdf4',
                  border: '1px solid #22c55e',
                  borderLeft: '4px solid #22c55e',
                  borderRadius: '6px',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: '0.25rem'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ fontSize: '0.85rem', fontWeight: 'bold', color: '#15803d' }}>
                      Cliente Registrado ✓
                    </span>
                    <button
                      onClick={() => {
                        setSelectedClient(null);
                        setSearchPhone('');
                      }}
                      style={{
                        border: 'none',
                        background: 'none',
                        color: '#ef4444',
                        fontSize: '0.75rem',
                        fontWeight: 'bold',
                        cursor: 'pointer'
                      }}
                    >
                      Cambiar
                    </button>
                  </div>
                  <div style={{ fontSize: '0.8rem', color: '#1e293b' }}>
                    <strong>Nombre:</strong> {selectedClient.nombre || selectedClient.displayName}<br />
                    <strong>Email:</strong> {selectedClient.email}<br />
                    <strong>Teléfono:</strong> {selectedClient.telefono}<br />
                    <strong>Compras Realizadas:</strong> {selectedClient.comprasRealizadas ?? 0}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="cart-content-wrapper">
          <CartView />

          <div className="cart-summary">
            <div className="summary-row">
              <span>Subtotal:</span>
              <span>${subtotal?.toFixed(2) || '0.00'}</span>
            </div>
            <div className="summary-row">
              <span>Impuesto (16%):</span>
              <span>${tax?.toFixed(2) || '0.00'}</span>
            </div>
            <div className="summary-row total">
              <span>Total:</span>
              <span>${total?.toFixed(2) || '0.00'}</span>
            </div>
            <Button
              variant="primary"
              className="checkout-btn"
              onClick={() => navigate('/checkout', { state: { selectedClient } })}
              disabled={!cartItems || cartItems.length === 0 || (clientTab === 'buscar' && !selectedClient)}
            >
              Cobrar
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}
